import{_ as e}from"./chunks/logo.PPNoggWL.js";import{_ as o,o as a,c as i,ag as s}from"./chunks/framework.DQQHyi2x.js";const g=JSON.parse('{"title":"Updating AtmosphericX","description":"","frontmatter":{"layout":"doc","next":{"text":"Troubleshooting","link":"/pages/installation/troubleshooting"},"prev":{"text":"Post Installation","link":"/pages/installation/post-installation"}},"headers":[],"relativePath":"pages/installation/updating-atmosphericx.md","filePath":"pages/installation/updating-atmosphericx.md"}'),r={name:"pages/installation/updating-atmosphericx.md"};function n(c,t,l,p,d,u){return a(),i("div",null,[...t[0]||(t[0]=[s('<img src="'+e+'" alt="AtmosphericX Logo" width="200" style="display:block;margin:0 auto;"><small class="page-author">Written By: <b>KiyoWx</b></small><br><small class="last-updated">Last Updated: <b>Feb 27th, 2026</b></small><br><h1 id="updating-atmosphericx" tabindex="-1">Updating AtmosphericX <a class="header-anchor" href="#updating-atmosphericx" aria-label="Permalink to &quot;Updating AtmosphericX&quot;">​</a></h1><hr><p>AtmosphericX can be updated easily by running the <code>update.sh</code> script found under the <code>build-tools</code> directory in the project.</p><div class="warning custom-block"><p class="custom-block-title">Version Compatibility</p><p>The <code>update.sh</code> script is only available for v8 or higher. Updating v7 instances using this script will <strong>not work</strong>. Please perform a fresh installation if you are on v7.</p></div><h2 id="how-does-it-work" tabindex="-1">How does it work? <a class="header-anchor" href="#how-does-it-work" aria-label="Permalink to &quot;How does it work?&quot;">​</a></h2><p>The script compares your current version (stored in <code>/storage/store/version.bin</code>) with the latest commit on <code>beta/main</code>. For private development builds, you can pass a GitHub Classic Token as a parameter.</p><div class="tip custom-block"><p class="custom-block-title">Forcing an Update</p><p>If your version matches the latest, the script will do nothing. To force an update, edit <code>version.bin</code> and set a lower version number.</p></div><h2 id="will-my-configurations-be-saved" tabindex="-1">Will my configurations be saved? <a class="header-anchor" href="#will-my-configurations-be-saved" aria-label="Permalink to &quot;Will my configurations be saved?&quot;">​</a></h2><p>AtmosphericX prompts you to back up your configuration files before updating. Always accept this step to avoid losing custom settings. Some updates may replace existing configuration files with new versions. This can overwrite custom settings. AtmosphericX uses SHA-1 checksums to verify configuration integrity. A console warning simply means your configuration differs from the official release. This is normal! Backing up ensures you can restore your custom settings after the update.</p><div class="info custom-block"><p class="custom-block-title">Backup Reminder</p><p>Always back up your configuration files before running <code>update.sh</code>. This ensures you can restore custom settings if they are overwritten during the update process.</p></div>',15)])])}const f=o(r,[["render",n]]);export{g as __pageData,f as default};
